RestCrudAdapter:
export declare class RestCrudAdapter implements ICrudAdapter {
    /**
     * REST backends typically enforce auth/row-level scoping server-side, so
     * the framework's client-side visibility gate is redundant. We still run
     * schema validation on writes via `validateWithSchema` when the caller
     * provides one, but we do NOT filter fields on reads — the server is
     * the authoritative gate.
     */
    readonly dbLevelSecurity = true;
    private readonly baseUrl;
    private readonly credentials;
    private readonly baseHeaders;
    private readonly beforeRequest;
    private readonly pathResolver;
    private readonly listTransform;
    private readonly fetchImpl;
    constructor(config?: RestCrudAdapterConfig);
    private buildInit;
    private doFetch;
    get<T>(collection: string, id: string, _schema?: dndevSchema<unknown>, options?: CrudOperationOptions): Promise<T | null>;
    query<T>(collection: string, options: QueryOptions, _schema?: dndevSchema<unknown>, _schemaType?: 'list' | 'listCard', operationOptions?: CrudOperationOptions): Promise<PaginatedQueryResult<T>>;
    add<T>(collection: string, data: T, schema?: dndevSchema<T>, options?: CrudOperationOptions): Promise<{
        id: string;
        data: Record<string, unknown>;
    }>;
    set<T>(collection: string, id: string, data: T, schema?: dndevSchema<T>, options?: CrudOperationOptions): Promise<void>;
    update<T>(collection: string, id: string, data: Partial<T>, options?: CrudOperationOptions): Promise<void>;
    delete(collection: string, id: string, options?: CrudOperationOptions): Promise<void>;
    /**
     * Bulk transactional operation.
     *
     * Wire contract: `POST ${baseUrl}/${collection}/bulk` with a
     * `BulkRequestSchema`-shaped body. The server runs every op in a single
     * transaction and returns a `BulkResponseSchema`-shaped summary. Auth
     * headers, `credentials`, and `beforeRequest` follow the same rules as
     * `add()`.
     *
     * Contract guarantees (server-enforced, mirrored client-side):
     *   1. Atomic — all ops commit or none do.
     *   2. Collision rejection — same id in `updates`+`deletes` or
     *      `inserts`+`updates` throws `BulkCollisionError` **before** any
     *      fetch. The collision error is re-thrown unwrapped so callers can
     *      `instanceof` it.
     *   3. Empty bulk (`{}`, or all-empty buckets) short-circuits to a zeroed
     *      result with no network call.
     *   4. Input order preserved per bucket in the returned ids.
     *
     * When `schema` is provided, each `inserts[i]` is validated via
     * `validateWithSchema` — same contract as `add()`. `updates[*].patch` is
     * not validated here because it is a partial view of the entity (mirrors
     * the single-row `update()`).
     *
     * @example
     * const result = await adapter.bulk('events', {
     *   inserts: [{ title: 'A' }],
     *   updates: [{ id: 'e1', patch: { title: 'renamed' } }],
     *   deletes: ['e2'],
     * }, eventSchema);
     * result.insertedIds; // ['evt_…']
     * result.updatedIds;  // ['e1']
     * result.deletedIds;  // ['e2']
     */
    bulk<T extends Record<string, unknown>>(collection: string, ops: BulkOperations<T>, schema?: dndevSchema<T>, options?: CrudOperationOptions): Promise<BulkResult>;
    subscribe?<T>(_collection: string, _id: string, _callback: DocumentSubscriptionCallback<T>, _schema?: dndevSchema<unknown>): () => void;
    subscribeToCollection?<T>(_collection: string, _options: QueryOptions, _callback: CollectionSubscriptionCallback<T>, _schema?: dndevSchema<unknown>): () => void;
}

buildQueryString:
/**
 * Build a URL-safe query string from a `QueryOptions` object. Returns
 * an empty string when there are no options. The leading `?` IS included
 * on non-empty output so callers can concat directly.
 */
export declare function buildQueryString(options: QueryOptions | undefined): string;

BeforeRequestHook:
export type BeforeRequestHook = (req: RequestInit_, context: {
    collection: string;
    operation: string;
    id?: string;
}

ListResponseTransform:
/**
 * Optional transformer for list responses. Some backends wrap lists in
 * `{ items: [...] }` or `{ results: [...] }` instead of the default
 * `{ data: [...] }`. Return a canonicalised `{ data, total?, nextCursor? }`.
 */
export type ListResponseTransform = (raw: unknown) => {
    data: unknown[];
    total?: number;
    nextCursor?: string | null;
}

PathResolver:
/**
 * Override the URL path for a given operation. Default resolver is
 * `${baseUrl}/${collection}[/${id}]`. Override when your backend uses a
 * different URL shape (e.g. `/api/v1/memories/owner/{ownerId}`).
 */
export type PathResolver = (baseUrl: string, collection: string, operation: 'get' | 'query' | 'add' | 'set' | 'update' | 'delete', id?: string) => string;

RestCrudAdapterConfig:
/**
 * Configuration for `new RestCrudAdapter(config)`.
 */
export interface RestCrudAdapterConfig {
    /**
     * Base URL for the REST API, without trailing slash. Default:
     * `'/api/crud'`. Must be same-origin unless the server serves CORS headers.
     */
    readonly baseUrl?: string;
    /**
     * `credentials` mode for fetch. Default: `'include'` so session cookies
     * are sent on every request. Set to `'omit'` for Bearer-token auth.
     */
    readonly credentials?: RequestCredentials;
    /**
     * Static headers merged into every request (Content-Type is set
     * automatically for requests with a JSON body).
     */
    readonly headers?: Record<string, string>;
    /**
     * Per-request hook — last-chance mutation of the Request before fetch.
     */
    readonly beforeRequest?: BeforeRequestHook;
    /**
     * Override the default URL shape. Default is the classic
     * `${baseUrl}/${collection}[/${id}]` RESTful pattern.
     */
    readonly pathResolver?: PathResolver;
    /**
     * Override the default list response shape (`{ data, total?, nextCursor? }`).
     */
    readonly listResponseTransform?: ListResponseTransform;
    /**
     * Default `fetch` implementation. Defaults to `globalThis.fetch`. Override
     * for custom transports, retries, or testing with a mock.
     */
    readonly fetch?: typeof fetch;
}

createBulkHandler:
/**
 * Build a framework-agnostic bulk handler for one entity. The returned
 * function is pure with respect to the inbound request — it parses the
 * body, authenticates, runs `executeBulk`, and returns a
 * {@link BulkResponsePayload} the adapter writes back.
 *
 * Error classification:
 *  - {@link BulkRequestSchema} failure → 400.
 *  - `authenticate()` rejection → 401.
 *  - {@link BulkCollisionError} → 409.
 *  - Any other thrown value → 500 with `err.message` only (no stack).
 *
 * The handler never throws — every error path returns a payload. This
 * keeps adapters trivial (no try/catch around the call).
 *
 * @template TRow - Entity row type.
 * @param options - Handler configuration.
 * @returns A request-agnostic handler.
 *
 * @example
 * ```ts
 * import { createBulkHandler } from '@donotdev/restcrud/server';
 *
 * const handle = createBulkHandler({
 *   entity: eventEntity,
 *   createSchema: eventCreateSchema,
 *   updateSchema: eventUpdateSchema,
 *   access: { create: 'user', update: 'user', delete: 'user' },
 *   authenticate: async (req) => {
 *     const token = req.headers['authorization'];
 *     if (typeof token !== 'string') throw new Error('Missing bearer token');
 *     return verifyJwt(token.replace(/^Bearer /, ''));
 *   },
 *   transact: async ({ inserts, updates, deletes }) => {
 *     return db.transaction(async (tx) => {
 *       for (const { id, row } of inserts) await tx.insert(events).values({ id, ...row });
 *       for (const { id, patch } of updates) await tx.update(events).set(patch).where(eq(events.id, id));
 *       for (const id of deletes) await tx.delete(events).where(eq(events.id, id));
 *       return {
 *         insertedIds: inserts.map((i) => i.id),
 *         updatedIds: updates.map((u) => u.id),
 *         deletedIds: [...deletes],
 *       };
 *     });
 *   },
 * });
 *
 * const payload = await handle({ headers, body, collection: 'events' });
 * ```
 *
 * @since 0.2.0
 */
export declare function createBulkHandler<TRow = unknown>(options: CreateBulkHandlerOptions<TRow>): (req: BulkRequestContext) => Promise<BulkResponsePayload>;

BulkRequestContext:
/**
 * Framework-agnostic request context passed to the core handler. Each
 * adapter is responsible for extracting this from its native request type.
 *
 * @since 0.2.0
 */
export interface BulkRequestContext {
    /**
     * Inbound request headers. Shape matches Node's `IncomingHttpHeaders`
     * (lower-cased keys, values may be `string | string[] | undefined`) so
     * every framework's headers object maps cleanly without normalisation.
     */
    headers: Record<string, string | string[] | undefined>;
    /**
     * Parsed JSON body. Adapters MUST parse the raw body before invoking the
     * handler — the core never reads streams. `undefined` and non-objects
     * are rejected by {@link BulkRequestSchema}.
     */
    body: unknown;
    /**
     * Collection name extracted from the URL segment. Consumer-extracted
     * because URL routing is framework-specific (`req.params.collection` in
     * Express, `c.req.param('collection')` in Hono, `params.collection` in
     * Next's App Router handler, etc.).
     */
    collection: string;
}

BulkResponsePayload:
/**
 * Framework-agnostic response shape. Adapters map `status` + `body` to
 * their native response type.
 *
 * @since 0.2.0
 */
export interface BulkResponsePayload {
    /** HTTP status code. See file-level docs for the code contract. */
    status: number;
    /** JSON-serialisable response body. */
    body: BulkResponse | {
        error: string;
    };
}

CreateBulkHandlerOptions:
/**
 * Options for {@link createBulkHandler}.
 *
 * @template TRow - Row type for the entity (documentation only; runtime is
 *   opaque because the wire schemas are structural).
 *
 * @since 0.2.0
 */
export interface CreateBulkHandlerOptions<TRow = unknown> {
    /**
     * Entity metadata. Currently only `collection` is consulted on the
     * server — kept as a full Entity so future additions (audit hook names,
     * soft-delete flags) don't break the signature.
     */
    entity: Entity;
    /** Valibot schema validating each insert row. */
    createSchema: dndevSchema<TRow>;
    /** Valibot schema validating each update patch. */
    updateSchema: dndevSchema<Partial<TRow>>;
    /** Per-bucket required roles. Forwarded to `executeBulk`. */
    access: EntityAccessConfig;
    /**
     * Resolve `{ uid, userRole }` from the inbound request. Consumer-supplied
     * because every REST stack has a different auth layer:
     *  - cookie-session middleware (Express + express-session)
     *  - Bearer JWT (Hono + jose)
     *  - Next.js server-side `cookies()` + DB lookup
     *  - Fastify + @fastify/jwt
     *
     * Throw (or return a rejected promise) to deny access — the core maps
     * any rejection to `401 Unauthorized` with the error's message.
     */
    authenticate: (req: BulkRequestContext) => Promise<{
        uid: string;
        userRole: UserRole;
    }>;
    /**
     * Target-specific storage — same contract as `executeBulk`'s `transact`.
     * Must run all three buckets inside one atomic transaction.
     */
    transact: ExecuteBulkParams['transact'];
    /** Optional id minting. See {@link ExecuteBulkParams.mintInsertId}. */
    mintInsertId?: ExecuteBulkParams['mintInsertId'];
    /** Optional insert metadata hook. */
    stampInsertMetadata?: ExecuteBulkParams['stampInsertMetadata'];
    /** Optional update metadata hook. */
    stampUpdateMetadata?: ExecuteBulkParams['stampUpdateMetadata'];
    /** Optional audit hook fired once on success with the three op counts. */
    audit?: ExecuteBulkParams['audit'];
}

NextAppRouteContext:
/**
 * Shape of the second argument passed by Next 13+ App Router dynamic
 * route handlers. `params` is sync in Next 13/14 and async (thenable) in
 * Next 15+ — we handle both via `await`.
 *
 * @since 0.2.0
 */
export interface NextAppRouteContext {
    params: {
        collection?: string;
    } | Promise<{
        collection?: string;
    }>;
}

